var C={"party": [{"id": "ludo", "name": "路德", "class": "explorer", "mainAttr": "str", "sprite": "ludo", "base": {"str": 4, "agi": 3, "int": 2}, "growth": {"str": 2, "agi": 1, "int": 1}, "startLevel": 1, "startEq": {"weapon": "short_sword", "armor": "traveler_garb", "boots": "leather_boots", "wrist": "cloth_wraps"}, "story": ["芳蕾鎮鐵匠漢克與瑪莎的獨生子，十五歲。", "從小聽著往來旅人的冒險故事長大，一心嚮往外面的世界，", "行動總是比思考快半拍，闖禍後道歉的速度倒是全鎮最快。", "十五歲那年，偷跟著借宿鎮上的冒險者亞倫進入北方礦山，", "在深處遭遇了不該存在的魔物——亞倫為掩護他而下落不明。", "「我要成為真正的冒險者，查出那一天的真相。」"]}, {"id": "marin", "name": "瑪琳", "class": "explorer", "mainAttr": "agi", "sprite": "marin", "base": {"str": 3, "agi": 4, "int": 3}, "growth": {"str": 1, "agi": 2, "int": 1}, "startLevel": 1, "startEq": {"weapon": "hunting_knife", "armor": "traveler_garb", "boots": "leather_boots", "acc1": "agate_charm"}, "story": ["旅店老闆娘朵拉的女兒，與路德一起長大的青梅竹馬。", "冷靜務實，是路德闖禍前的最後一道煞車——雖然常常煞不住。", "身手靈巧，一手獵刀是幫旅店處理野味時練出來的本事，", "戴著的瑪瑙護符，是母親朵拉在她出發前偷偷塞進行囊的。", "礦山意外後，看著把自己關在房裡的路德，她只說了一句：", "「要去就一起去。你一個人，我不放心。」"]}, {"id": "aaron", "name": "亞倫", "class": "veteran", "mainAttr": "str", "sprite": "aaron", "base": {"str": 30, "agi": 24, "int": 14}, "growth": {}, "startLevel": 20, "guest": true, "startEq": {"weapon": "iron_sword", "armor": "leather_vest", "boots": "swift_boots", "wrist": "iron_bracer"}, "story": ["借宿芳蕾鎮的 A 級冒險者。話少，劍快。", "來歷成謎，只知道他一直在調查北方礦山的異變。", "看出路德眼裡的光和「年輕時的某人」很像，", "嘴上嫌麻煩，卻默許了少年的跟隨。", "礦山深處遭遇異變魔影時，他擋在路德身前——", "「快跑！把這裡的事告訴鎮上的人！」", "此後下落不明。他留下的劍術與背影，成了路德的目標。"]}], "derived": {"hpBase": 30, "hpPerStr": 8, "mpBase": 8, "mpPerInt": 5, "weaponAtk": 6, "pointsPerLevel": 3, "skillPointsPerLevel": 1, "skillMaxLv": 10, "skillPowerPerLv": 0.15, "expBase": 10, "expCoef": 8, "expPow": 1.4, "matkPerInt": 2, "mdefPerInt": 0.8, "dodgePerAgi": 1.5, "dodgeCap": 30, "critBase": 6.25, "critPerAgi": 0.15}, "equipment": [{"id": "short_sword", "name": "短劍", "slot": "weapon", "patk": 2, "desc": "鎮上鐵匠隨手打的入門短劍，輕便好上手。", "buy": 40, "sell": 12}, {"id": "hunting_knife", "name": "獵刀", "slot": "weapon", "patk": 1, "crit": 4, "d