  var set={};
  for(var i=0;i<inv.length;i++){if(EQ[inv[i]]&&EQ[inv[i]].slot===tp)set[inv[i]]=1;}
  if(cur)set[cur]=1;
  var ring=[null].concat(Object.keys(set).sort());
  if(ring.length<2){sfx("cancel.mp3");return false;}
  var next=ring[(ring.indexOf(cur)+1)%ring.length];
