var DLG = {"tina": [{"when": "step==0", "name": "緹娜", "lines": ["這不是路德嗎？要去礦山見習？", "等你正式登錄的那天，公會隨時歡迎你。"]}, {"when": "ch1==2", "name": "緹娜", "lines": ["委託完成確認——哥布林頭目討伐！", "報酬 200 金幣已支付。你們是本鎮的驕傲！", "（第一章完──「重返礦山」即將開放）"], "action": "ch1_reward"}, {"when": "ch1==1", "name": "緹娜", "lines": ["委託進行中：討伐東之森深處的哥布林頭目。", "牠就在森林最東邊的空地，小心點！"]}, {"when": "ch2>=1", "name": "緹娜", "lines": ["礦坑的委託，是老葛雷私下拜託你們的吧？", "那些失蹤的礦工……公會這邊也一直很掛心。", "小心點，別逞強——活著回來才是好冒險者。"]}, {"when": "ch1==3", "name": "緹娜", "lines": ["哥布林頭目的委託已經結案囉，辛苦了！", "接下來想找活兒的話，水井旁的老葛雷正在找人幫忙。"]}, {"when": "reg==1", "name": "緹娜", "lines": ["有新委託喔——農家回報東之森的哥布林越來越囂張，", "牠們的頭目就盤踞在森林深處。", "【委託】討伐哥布林頭目（報酬 200G）。接受嗎？就當你接受了！", "頭目比雜魚強得多——建議練到 Lv5、跟漢克拿把好劍再去。"], "action": "ch1_take"}, {"when": "step>=3", "name": "緹娜", "lines": ["歡迎來到冒險者公會！要登錄成為冒險者嗎？", "……路德和瑪琳，兩位都登錄完成！", "從今天起你們就是 F 級冒險者了。委託隨時來找我。"], "action": "register"}], "dora": [{"when": "step==0", "name": "朵拉", "lines": ["要跟亞倫先生出門？路上小心。", "回來我煮好吃的等你們。"]}, {"when": "always", "name": "朵拉", "lines": ["累了吧？床鋪都幫你們鋪好了。", "（隊伍完全恢復了！）"], "action": "heal"}], "sister": [{"when": "ch2>=2", "name": "希雅修女", "lines": ["你們從礦山帶回來的……不只是疲憊。", "那是亡者未能安息的哀嘆。願蓋婭女神接引他們。", "（隊伍完全恢復了！）", "……路德，女神在你身上的記號，又亮了一分。"], "action": "heal"}, {"when": "step>=3", "name": "希雅修女", "lines": ["蓋婭女神看顧著每一位旅人。", "……女神在你身上留了記號呢。願風平息。", "（隊伍完全恢復了！）"], "action": "heal"}], "barton": [{"when": "step==0", "name": "巴頓鎮長", "lines": ["聽說亞倫先生要帶你去礦山見習？", "好好跟著學，別亂跑。"]}, {"when": "ch2>=3", "name": "巴頓鎮長", "lines": ["礦工失蹤的事……我早該多過問一句的。", "孩子，你們比這鎮上所有大人都勇敢。", "把礦山看到的一切，原原本本告訴大城的人吧。"]}, {"when": "ch1==3", "name": "巴頓鎮長", "lines": ["哥布林的事多虧你們了。", "但礦山的異變……我總覺得沒那麼簡單。"]}, {"when": "always", "name": "巴頓鎮長", "lines": ["礦山最近不太平靜，連老獵人都不敢靠近。", "亞倫先生的事……我很遺憾。孩子，別勉強自己。"]}], "hank": [{"when": "gotSword==1", "name": "漢克", "lines": ["要補貨就直說，鐵匠鋪隨時開著。"], "action": "shop_hank"}, {"when": "ch1>=1", "name": "漢克", "lines": ["……路德，你也要出去闖了啊。", "拿去，我打的劍。別死在外面。", "（獲得『鐵劍』！開啟 選單→裝備 分頁換上它）", "往後要打點裝備，儘管來鐵匠鋪。"], "action": "shop_hank_gift"}, {"when": "reg==1", "name": "漢克", "lines": ["冒險者？裝備可不能馬虎。", "來，看看我的貨。"], "action": "shop_hank"}, {"when": "step==0", "name": "漢克", "lines": ["哼，礦山？", "……跟緊亞倫先生，別給他添麻煩。"]}, {"when": "always", "name": "漢克", "lines": ["冒險者？哼，那不是鬧著玩的。", "你亞倫大哥那麼強的人都……算了。要去就去吧。"]}], "martha": [{"when": "gotRing==0", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "這枚戒指你戴著——是我年輕時你爸打的，保平安。", "（獲得『活力戒指』！開啟 選單→裝備 可以裝上）"], "action": "give_ring"}, {"when": "always", "name": "瑪莎", "lines": ["你這孩子，越來越像年輕時的你爸了。", "路上一定要吃飽穿暖，聽到沒？"]}], "gid": [{"when": "gotPotion==1", "name": "吉德", "lines": ["歡迎光臨！補給要趁早，這是老冒險者的鐵則。"], "action": "shop_gid"}, {"when": "always", "name": "吉德", "lines": ["藥水備齊再出門，這是老冒險者的鐵則！", "（先送你 2 瓶藥水，別客氣。）", "要看看我店裡的商品嗎？"], "action": "shop_gid_gift"}], "gray": [{"when": "relic==1", "name": "老葛雷", "lines": ["這頂頭盔……是阿吉的！你們在裡頭找到的？", "（老葛雷的手抖個不停）……謝謝你們，把他的東西帶了回來。", "這是我僅有的一點謝禮，別嫌少。", "（獲得 100 金幣）"], "action": "relic_turnin"}, {"when": "ch2==3", "name": "老葛雷", "lines": ["那些孩子……總算能入土為安了。", "你們替這座礦山、也替我這老頭子，了了一樁心事。", "剩下的——深處那股邪氣的源頭，就拜託你們了。"]}, {"when": "ch2==2", "name": "老葛雷", "lines": ["你們臉色不對……在裡頭看到什麼了？", "……戴著礦工帽、掄著鎬子的骷髏？那就是我那些老夥計沒錯了。", "（老葛雷沉默了好久）謝謝你們告訴我真相。這點心意收下。", "聽說深處的落石被你們清開了？那底下的東西，才是禍首。快去回報鎮長吧。"], "action": "ch2_report"}, {"when": "ch2==1", "name": "老葛雷", "lines": ["礦坑外圍就從鎮北的舊軌道進去。", "失蹤的老夥計要是還在……不，你們親眼去看看吧。", "（記得先把裝備和藥水在鎮上備齊）"]}, {"when": "ch1==3", "name": "老葛雷", "lines": ["解決了哥布林？好身手。", "那……礦坑的事，能拜託你們嗎？我的老夥計們一個接一個失蹤，", "官府當是逃工不管，可我知道——他們絕不會丟下家人跑掉。", "【委託】重返北方礦山外圍，查明礦工失蹤的真相。接下嗎？就當你們答應了。"], "action": "ch2_take"}, {"when": "step==0", "name": "老葛雷", "lines": ["那礦坑二十年前就封了……最近夜裡卻有聲音。", "要進去？……跟緊亞倫先生。"]}, {"when": "always", "name": "老葛雷", "lines": ["那礦坑二十年前就封了……最近夜裡卻有聲音。", "你們就是在裡面出事的吧。唉，可憐的亞倫先生。"]}], "mira": [{"when": "mira2==2", "name": "米拉", "lines": ["那些鏡草夠我熬好一陣子的藥了，真是幫了大忙！", "路上也別忘了照顧自己的傷。"]}, {"when": "herb==3", "name": "米拉", "lines": ["三株鏡草都採齊了？太好了！", "來，這些藥水你們拿去——採藥的謝禮。", "（獲得『藥水』×3！）"], "action": "mira_reward"}, {"when": "mira2==1", "name": "米拉", "lines": ["東之森裡三株會發光的『鏡草』，就麻煩你們了。", "它們喜歡長在水邊和大石頭旁。"]}, {"when": "gotEar==0", "name": "米拉", "lines": ["東之森的藥草最近都採不到了……草叢裡老是冒出怪物。", "你們要進森林嗎？能不能順手幫我採三株『鏡草』回來？", "對了，這耳環是我在森林邊撿到的，先送你們——就當訂金。", "（獲得『凝神耳環』！）", "（【支線】到東之森採集鏡草×3）"], "action": "mira_start"}, {"when": "always", "name": "米拉", "lines": ["鏡草要三株才夠熬一鍋藥。", "東之森的水邊和大石頭旁比較好找。"]}], "guard": [{"when": "ch1==3", "name": "羅素隊長", "lines": ["南方大道還在封鎖中。", "等王都的指示一到就放行——你們的事蹟我會寫進報告。"]}, {"when": "always", "name": "羅素隊長", "lines": ["前方道路因魔物騷動封閉中，王都的援軍還沒到。", "想去大城的話，再等等吧。"]}]};
var CUTS = {"prologue_town": {"once": "c_pro_town", "lines": [["瑪琳", "路德！聽說你要跟亞倫先生去礦山見習？"], ["路德", "嗯！我很快就回來——等著聽我的冒險故事吧！"], ["亞倫", "（在鎮北等著）……準備好了就從北邊出口出發。想先逛逛鎮子也行。"], ["", "（可以先和鎮民聊聊。準備好了就走北邊出口前往礦山）"]]}, "mine_intro": {"once": "c_mine_intro", "lines": [["亞倫", "跟緊我，路德。礦山不是給小孩玩的地方。"], ["路德", "我、我才不是小孩！我十五歲了！"], ["亞倫", "……哼。前面的碎石地會竄出魔物，正好給你練練手。"], ["", "（教學：走進碎石地會遭遇戰鬥。方向鍵移動，往北邊的礦坑口前進）"]]}, "cave_intro": {"once": "c_cave_intro", "lines": [["亞倫", "……深處的氣息不對勁。跟在我身後，別亂跑。"], ["路德", "（好冷……這裡真的只是廢棄礦坑嗎？）"]]}, "demon_pre": {"once": "c_demon", "lines": [["？？？", "（低沉的咆哮迴盪在洞穴深處──）"], ["亞倫", "趴下！路德──這傢伙不是這裡該有的東西！"], ["", "（撐過 3 回合！）"]], "battle": "prologue_demon"}, "demon_post": {"lines": [["亞倫", "（擋在路德身前）……快跑！把這裡的事告訴鎮上的人！"], ["路德", "亞倫大哥──！！"], ["", "──三天後，芳蕾鎮。"]], "transfer": ["Town", "home"], "setstep": 3}, "town_start": {"once": "c_town", "lines": [["瑪琳", "路德！你總算肯出房門了。"], ["瑪琳", "……亞倫先生的事，不是你的錯。"], ["路德", "瑪琳。我決定了——我要成為真正的冒險者，查出那天的真相。"], ["瑪琳", "一個人？想得美。要去，就一起去。"], ["", "（瑪琳加入了隊伍！先去公會找緹娜登錄吧）"]], "party": ["ludo", "marin"], "setstep": 4}, "mine_truth": {"once": "c_mine_truth", "lines": [["路德", "（這裡的空氣……比序章那次更冷了。）"], ["瑪琳", "路德，那邊有東西在動——是礦工？他們還活著？！"], ["路德", "不對……瑪琳，退後！牠的臉……牠根本沒有臉！"], ["瑪琳", "拿著鎬子、戴著礦工帽的骷髏……老葛雷說的失蹤礦工，難道就是……"], ["路德", "（他們早就死了。是有人……把他們變成了這個樣子。）"], ["", "（深處的舊礦道被落石半掩，一頭巨影在崩石後低吼——先解決擋路的東西）"]]}, "mine_after": {"once": "c_mine_after", "lines": [["", "（洞熊倒下，崩石隨著牠的重量嘩啦鬆開，露出一道向下的黑暗礦道）"], ["瑪琳", "這股味道……和那天，我們遇上那東西的時候一模一樣。"], ["路德", "下面有東西。骷髏、洞熊……都是被它從這裡……"], ["路德", "（亞倫大哥……當年擋在我面前的，是不是也和這底下的東西有關？）"], ["", "（深處的路開了。先回鎮上把所見告訴老葛雷與鎮長吧）"]]}};
var CONTENT = {"party": [{"id": "ludo", "name": "路德", "class": "explorer", "mainAttr": "str", "sprite": "ludo", "base": {"str": 4, "agi": 3, "int": 2}, "growth": {"str": 2, "agi": 1, "int": 1}, "startLevel": 1, "startEq": {"weapon": "short_sword", "armor": "traveler_garb", "boots": "leather_boots", "wrist": "cloth_wraps"}, "story": ["芳蕾鎮鐵匠漢克與瑪莎的獨生子，十五歲。", "從小聽著往來旅人的冒險故事長大，一心嚮往外面的世界，", "行動總是比思考快半拍，闖禍後道歉的速度倒是全鎮最快。", "十五歲那年，偷跟著借宿鎮上的冒險者亞倫進入北方礦山，", "在深處遭遇了不該存在的魔物——亞倫為掩護他而下落不明。", "「我要成為真正的冒險者，查出那一天的真相。」"]}, {"id": "marin", "name": "瑪琳", "class": "explorer", "mainAttr": "agi", "sprite": "marin", "base": {"str": 3, "agi": 4, "int": 3}, "growth": {"str": 1, "agi": 2, "int": 1}, "startLevel": 1, "startEq": {"weapon": "hunting_knife", "armor": "traveler_garb", "boots": "leather_boots", "acc1": "agate_charm"}, "story": ["旅店老闆娘朵拉的女兒，與路德一起長大的青梅竹馬。", "冷靜務實，是路德闖禍前的最後一道煞車——雖然常常煞不住。", "身手靈巧，一手獵刀是幫旅店處理野味時練出來的本事，", "戴著的瑪瑙護符，是母親朵拉在她出發前偷偷塞進行囊的。", "礦山意外後，看著把自己關在房裡的路德，她只說了一句：", "「要去就一起去。你一個人，我不放心。」"]}, {"id": "aaron", "name": "亞倫", "class": "veteran", "mainAttr": "str", "sprite": "aaron", "base": {"str": 30, "agi": 24, "int": 14}, "growth": {}, "startLevel": 20, "guest": true, "startEq": {"weapon": "iron_sword", "armor": "leather_vest", "boots": "swift_boots", "wrist": "iron_bracer"}, "story": ["借宿芳蕾鎮的 A 級冒險者。話少，劍快。", "來歷成謎，只知道他一直在調查北方礦山的異變。", "看出路德眼裡的光和「年輕時的某人」很像，", "嘴上嫌麻煩，卻默許了少年的跟隨。", "礦山深處遭遇異變魔影時，他擋在路德身前——", "「快跑！把這裡的事告訴鎮上的人！」", "此後下落不明。他留下的劍術與背影，成了路德的目標。"]}], "derived": {"hpBase": 30, "hpPerStr": 8, "mpBase": 8, "mpPerInt": 5, "weaponAtk": 6, "pointsPerLevel": 3, "skillPointsPerLevel": 1, "skillMaxLv": 10, "skillPowerPerLv": 0.15, "expBase": 10, "expCoef": 8, "expPow": 1.4, "matkPerInt": 2, "mdefPerInt": 0.8, "dodgePerAgi": 1.5, "dodgeCap": 30, "critBase": 6.25, "critPerAgi": 0.15}, "equipment": [{"id": "short_sword", "name": "短劍", "slot": "weapon", "patk": 2, "desc": "鎮上鐵匠隨手打的入門短劍，輕便好上手。", "buy": 40, "sell": 12}, {"id": "hunting_knife", "name": "獵刀", "slot": "weapon", "patk": 1, "crit