  }
  var mf=one("MenuFace");
  if(mf){mf.hide(!opt.showFace);if(opt.showFace)mf.setAnimationName(opt.showFace);}
  var mmap=one("MenuMap");
  if(mmap)mmap.hide(!opt.showMap);
  if(mh){mh.hide(false);mh.setString((opt.hint||"")+"　　金幣 "+g.get("g_gold").getAsNumber());}
}
